import{_ as e,o,c as a,aa as n}from"./chunks/framework.GPvTQ_Wl.js";const p=JSON.parse('{"title":"Technical Limitations & Constraints","description":"Understand the technical limitations and constraints of modding the Total War: Rome II, Attila, and Thrones of Britannia engine. Coverage of UI restrictions, console input, and battle mode scripting.","frontmatter":{"title":"Technical Limitations & Constraints","description":"Understand the technical limitations and constraints of modding the Total War: Rome II, Attila, and Thrones of Britannia engine. Coverage of UI restrictions, console input, and battle mode scripting."},"headers":[],"relativePath":"guide/technical-limitations.md","filePath":"guide/technical-limitations.md","lastUpdated":1777579057000}'),i={name:"guide/technical-limitations.md"};function r(s,t,l,c,h,u){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h1><h2 id="mod-scope-philosophy" tabindex="-1">Mod Scope &amp; Philosophy <a class="header-anchor" href="#mod-scope-philosophy" aria-label="Permalink to &quot;Mod Scope &amp; Philosophy&quot;">​</a></h2><p>ConsulScriptum is a high-level automation and troubleshooting tool, <strong>not a low-level engine hack</strong>.</p><table tabindex="0"><thead><tr><th style="text-align:left;">What it IS</th><th style="text-align:left;">What it is NOT</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Non-invasive</strong> (.pack file mod).</td><td style="text-align:left;">A executable hack / external dll.</td></tr><tr><td style="text-align:left;">A high-level interface for official Lua APIs.</td><td style="text-align:left;">A low-level hook into internal game APIs.</td></tr><tr><td style="text-align:left;">A tool for changing current game state.</td><td style="text-align:left;">A way to modify how the game loads its own files.</td></tr><tr><td style="text-align:left;">A bridge for external script execution.</td><td style="text-align:left;">A bypass for core engine constraints.</td></tr></tbody></table><hr><div class="tip custom-block"><p class="custom-block-title">Help Improve This Project</p><p>Most of the limitations described below are due to hardcoded constraints of the game engine&#39;s UI system. If you are a modder and know a technical workaround for any of these issues (especially regarding keyboard events, custom fonts, or input focus), please <a href="https://discord.gg/6vm2M94vhX" target="_blank" rel="noreferrer">get in touch on Discord</a> or <a href="https://github.com/bukowa/ConsulScriptum/issues" target="_blank" rel="noreferrer">open an issue on GitHub</a>.</p></div><h2 id="console-input" tabindex="-1">Console input <a class="header-anchor" href="#console-input" aria-label="Permalink to &quot;Console input&quot;">​</a></h2><p>The console input component is a basic game engine TextInput element, which has several hardcoded restrictions that cannot be modified via scripts.</p><h5 id="no-enter-key" tabindex="-1"><strong>No Enter key.</strong> <a class="header-anchor" href="#no-enter-key" aria-label="Permalink to &quot;**No Enter key.**&quot;">​</a></h5><p>The game does not capture the &quot;Enter&quot; key as a submission trigger for this UI component. You must click the <strong>Send</strong> button to execute your input.</p><h5 id="no-arrow-key-history-navigation" tabindex="-1"><strong>No arrow key history navigation.</strong> <a class="header-anchor" href="#no-arrow-key-history-navigation" aria-label="Permalink to &quot;**No arrow key history navigation.**&quot;">​</a></h5><p>Keyboard events like the Up (↑) and Down (↓) arrow keys are not exposed to the modding API for this field. Use the on-screen <strong>↑</strong> and <strong>↓</strong> buttons next to the input to cycle through your command history.</p><h5 id="locked-cursor-in-history" tabindex="-1"><strong>Locked cursor in history.</strong> <a class="header-anchor" href="#locked-cursor-in-history" aria-label="Permalink to &quot;**Locked cursor in history.**&quot;">​</a></h5><p>When you restore a command from history using the arrow buttons, the cursor remains locked at the end of the line. You cannot click within the text or use the mouse to reposition the cursor for partial editing.</p><h5 id="no-tab-autocomplete" tabindex="-1"><strong>No tab autocomplete.</strong> <a class="header-anchor" href="#no-tab-autocomplete" aria-label="Permalink to &quot;**No tab autocomplete.**&quot;">​</a></h5><p>Standard Lua or console-style autocompletion (pressing Tab) is not supported by the game&#39;s internal text fields.</p><h5 id="input-truncation-character-limit" tabindex="-1"><strong>Input truncation (Character Limit).</strong> <a class="header-anchor" href="#input-truncation-character-limit" aria-label="Permalink to &quot;**Input truncation (Character Limit).**&quot;">​</a></h5><p>The game&#39;s input buffer silently truncates long strings, usually around 100-255 characters. If you paste a long script, the console may only receive the first few lines, leading to syntax errors like <code>unfinished string near &#39;&lt;eof&gt;&#39;</code>.</p><div class="tip custom-block"><p class="custom-block-title">Multi-line Scripts</p><p>The console is best for one-liners or running predefined commands.<br>For anything longer or more complex, use <a href="./scriptum-manual">Scriptum</a> to run files directly from your disk.</p></div><h2 id="console-output" tabindex="-1">Console output <a class="header-anchor" href="#console-output" aria-label="Permalink to &quot;Console output&quot;">​</a></h2><h5 id="you-cannot-copy-text-directly-from-the-ui" tabindex="-1"><strong>You cannot copy text directly from the UI.</strong> <a class="header-anchor" href="#you-cannot-copy-text-directly-from-the-ui" aria-label="Permalink to &quot;**You cannot copy text directly from the UI.**&quot;">​</a></h5><p>The output area is a read-only text component. Selecting, highlighting, or copying text with the mouse within the game window is not possible.</p><h5 id="how-to-copy-output" tabindex="-1"><strong>How to copy output:</strong> <a class="header-anchor" href="#how-to-copy-output" aria-label="Permalink to &quot;**How to copy output:**&quot;">​</a></h5><p>All console activity is automatically mirrored to a file called <code>consul.output</code> in your game root folder. Open this file in a text editor (like Notepad++) to copy, search, or share your results.</p><h5 id="the-scroll-slider-does-not-auto-reset" tabindex="-1"><strong>The scroll slider does not auto-reset.</strong> <a class="header-anchor" href="#the-scroll-slider-does-not-auto-reset" aria-label="Permalink to &quot;**The scroll slider does not auto-reset.**&quot;">​</a></h5><p>When new text is added, the scrollbar may not automatically jump to the bottom. You may need to scroll manually to see the latest results. Clicking <strong>Clear</strong> can help keep the view manageable.</p><h2 id="scriptum-panel" tabindex="-1">Scriptum panel <a class="header-anchor" href="#scriptum-panel" aria-label="Permalink to &quot;Scriptum panel&quot;">​</a></h2><p><strong>Slot Limit (10 Scripts).</strong> The panel is currently hard-capped at 10 script buttons. This is not a random number, but a technical compromise:</p><ul><li><strong>Rome II</strong>: The UI engine cannot create components on the fly. All 10 buttons are pre-built into the interface files.</li><li><strong>Attila / ToB</strong>: While they technically support dynamic lists, the 10-slot limit is maintained to keep the experience consistent across all supported games.</li></ul><div class="tip custom-block"><p class="custom-block-title">Pro Tip: Master Scripts</p><p>If you run out of slots, you can create a &quot;Master Script&quot; that uses Lua <code>dofile()</code> to execute multiple other scripts in sequence, or use the console to run one-off files.</p><p><strong>Need more slots?</strong> Please <a href="https://github.com/bukowa/ConsulScriptum" target="_blank" rel="noreferrer">reach out via GitHub</a>.</p></div><h2 id="battle-mode" tabindex="-1">Battle mode <a class="header-anchor" href="#battle-mode" aria-label="Permalink to &quot;Battle mode&quot;">​</a></h2><p>Access to the console during campaign battles is available natively in ToB, while Rome II and Attila require an experimental workaround.</p><p><strong>Technical Note</strong>: In Rome II and Attila, the game engine uses distinct &quot;modes&quot; for campaign and standalone battles. The campaign UI and scripting environment (which Consul depends on) are typically unloaded when a battle starts. Our workaround forces these interfaces to remain active, but this only works when the battle is launched from an active campaign session where the interfaces are already initialized.</p><p>See the full <a href="/guide/battle-mode-scripting">Battle Mode Scripting</a> guide for instructions and example scripts.</p><h2 id="total-war-attila-tob" tabindex="-1">Total War: Attila &amp; ToB <a class="header-anchor" href="#total-war-attila-tob" aria-label="Permalink to &quot;Total War: Attila &amp; ToB&quot;">​</a></h2><p>The Attila implementation is currently considered <strong>Alpha</strong>.</p><h5 id="legacy-ui-files" tabindex="-1"><strong>Legacy UI Files.</strong> <a class="header-anchor" href="#legacy-ui-files" aria-label="Permalink to &quot;**Legacy UI Files.**&quot;">​</a></h5><p>To maintain a unified experience and ensure stability, the Attila version reuses several core UI components and layout logic from the Rome II version. Because of this &quot;frankenstein&quot; approach, minor visual glitches or alignment issues in the console may occur.</p><h5 id="experimental-status-attila" tabindex="-1"><strong>Experimental Status (Attila).</strong> <a class="header-anchor" href="#experimental-status-attila" aria-label="Permalink to &quot;**Experimental Status (Attila).**&quot;">​</a></h5><p>While the core features (Consul Scripts, Scriptum, and Lua Console) are functional, the engine differences mean that Attila is currently considered more experimental than Rome II or ToB.</p><h5 id="stability-note-tob" tabindex="-1"><strong>Stability Note (ToB).</strong> <a class="header-anchor" href="#stability-note-tob" aria-label="Permalink to &quot;**Stability Note (ToB).**&quot;">​</a></h5><p>Thrones of Britannia is built on the most refined version of this engine branch. While it shares some of the &quot;Frankenstein&quot; UI traits of the Attila version, it is generally more stable and supports several features (like Battle Mode) natively.</p><div class="warning custom-block"><p class="custom-block-title">Bug Reports</p><p>If you encounter a UI crash or a script that behaves differently in Attila or ToB than in Rome II, please <a href="https://github.com/bukowa/ConsulScriptum/issues" target="_blank" rel="noreferrer">open an issue</a>.</p></div><h2 id="resolution-changes" tabindex="-1">Resolution Changes <a class="header-anchor" href="#resolution-changes" aria-label="Permalink to &quot;Resolution Changes&quot;">​</a></h2><p><strong>Changing screen resolution during an active session.</strong> The Total War UI engine does not always update component positions correctly when the screen resolution or UI scale is changed while the game is running.</p><ul><li><strong>Symptom</strong>: The Consul window may appear misplaced, stretched, or partially off-screen.</li><li><strong>Fix</strong>: Auto-correction logic will attempt to bring the Consul back to the center on the next toggle, but for full UI alignment restoration, you may need to reload the UI (e.g., by entering and exiting a battle, or restarting the game).</li></ul><div class="tip custom-block"><p class="custom-block-title">Restore Defaults</p><p>If the Consul UI remains broken or invisible after a resolution change, you can manually delete the <code>consul.config</code> file in your game root folder. This will reset all settings and UI positions to their defaults on the next launch.</p></div><hr>',48)])])}const m=e(i,[["render",r]]);export{p as __pageData,m as default};
